effect.script:
function animate(env,el,p) {
    let absTimeSeconds = env.frame/env.fps;
    let evolution = p.evolution + p.freq;

    var a = p.angle * (Math.PI / 180);
    var s = Math.sin(a);
    var c = Math.cos(a);

    let dx = AM.simplexNoise(evolution, p.seed*49235.319798);
    let dy = AM.simplexNoise(evolution+7468.329, p.seed*19337.940385);
    let dz = AM.simplexNoise(evolution+14192.277, p.seed*71401.168533);
    dx *= p.mag;
    dy *= p.mag * p.slack;
    dz *= p.zshake;

    let rx = dx * c - dy * s;
    let ry = dx * s + dy * c;

    el.transform.location.x += rx;
    el.transform.location.y += ry;
    el.transform.location.z += dz;
    return el;
}
